/*
 * COMPREHENSIVE CODE EXAMPLES: WITH vs WITHOUT PageFactory.initElements()
 */

// ============================================================================
// SCENARIO 1: WITH PageFactory.initElements() - YOUR CURRENT APPROACH ✅
// ============================================================================

import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.FindBy;
import org.openqa.selenium.support.PageFactory;
import java.util.List;

public class HeaderURLs_WITH_PageFactory {
    public WebDriver driver;

    public HeaderURLs_WITH_PageFactory(WebDriver driver) {
        this.driver = driver;
        PageFactory.initElements(driver, this);  // ← CRITICAL LINE
        // This line initializes all @FindBy annotated fields as proxies
    }

    @FindBy(xpath = "//header//a")
    public List<WebElement> headerURLs;  // ← NOW WORKS AUTOMATICALLY

    public List<WebElement> getHeaderURLs() {
        return headerURLs;  // ← Safe to use, already initialized
    }

    // RESULT: ✅ Works perfectly!
    // When you call new HeaderURLs_WITH_PageFactory(driver),
    // the headerURLs field is automatically populated with WebElements
}

// ============================================================================
// SCENARIO 2: WITHOUT PageFactory.initElements() - MANUAL APPROACH
// ============================================================================

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import java.util.List;

public class HeaderURLs_WITHOUT_PageFactory {
    public WebDriver driver;

    public HeaderURLs_WITHOUT_PageFactory(WebDriver driver) {
        this.driver = driver;
        // NO PageFactory.initElements(driver, this) here
        // You must manually find elements
    }

    // NO @FindBy annotations - they would be ignored anyway

    private By headerURLsLocator = By.xpath("//header//a");

    public List<WebElement> getHeaderURLs() {
        return driver.findElements(headerURLsLocator);  // ← MANUAL SEARCH
        // Finds elements every time this method is called
    }

    // RESULT: ✅ Also works, but requires manual element location
}

// ============================================================================
// SCENARIO 3: WITHOUT PageFactory BUT KEEPING @FindBy (BROKEN) ❌
// ============================================================================

public class HeaderURLs_BROKEN_Approach {
    public WebDriver driver;

    public HeaderURLs_BROKEN_Approach(WebDriver driver) {
        this.driver = driver;
        // NO PageFactory.initElements() - FORGOT TO ADD IT
    }

    @FindBy(xpath = "//header//a")
    public List<WebElement> headerURLs;  // ← @FindBy is just a decoration now!
    // This field will be NULL because @FindBy doesn't work without PageFactory

    public List<WebElement> getHeaderURLs() {
        return headerURLs;  // ← NullPointerException! 
    }

    // RESULT: ❌ CRASHES because headerURLs is null
}

// ============================================================================
// SCENARIO 4: WITH PageFactory + EXPLICIT WAITS (ADVANCED)
// ============================================================================

import org.openqa.selenium.support.ui.WebDriverWait;
import org.openqa.selenium.support.ui.ExpectedConditions;
import java.time.Duration;

public class HeaderURLs_WITH_PageFactory_And_Waits {
    public WebDriver driver;
    public WebDriverWait wait;

    public HeaderURLs_WITH_PageFactory_And_Waits(WebDriver driver) {
        this.driver = driver;
        this.wait = new WebDriverWait(driver, Duration.ofSeconds(10));
        PageFactory.initElements(driver, this);  // Initialize proxies
    }

    @FindBy(xpath = "//header//a")
    public List<WebElement> headerURLs;

    public List<WebElement> getHeaderURLs() {
        // Add explicit wait for safety
        wait.until(ExpectedConditions.presenceOfAllElementsLocatedBy(
            By.xpath("//header//a")
        ));
        return headerURLs;
    }

    // RESULT: ✅ Most robust approach
}

// ============================================================================
// PERFORMANCE COMPARISON
// ============================================================================

/*
WITH PageFactory:
  - Elements searched on FIRST ACCESS (lazy loading)
  - Proxies created during initialization
  - Memory: Low (proxies are lightweight)
  - Speed: Fast (cached after first access)
  - Stale element issues: Handled automatically

WITHOUT PageFactory (manual findElements):
  - Elements searched EVERY TIME method is called
  - No proxies, direct element collection
  - Memory: Higher (keeps list references)
  - Speed: Slower (re-searches each time)
  - Stale element issues: You must handle manually

Testing with 100 calls to getHeaderURLs():
  WITH PageFactory:    ~1000ms (search happens ~1-2 times max)
  WITHOUT PageFactory: ~3000ms (search happens 100 times)
*/

// ============================================================================
// YOUR PROJECT RECOMMENDATION
// ============================================================================

/*
 YOUR CURRENT CODE:
   - HeaderURLs extends BasePage
   - Uses @FindBy(xpath = "//header//a")
   - BasePage calls PageFactory.initElements(driver, this)

✅ DECISION: KEEP IT AS IS

WHY?
1. ✅ Your code is correctly structured
2. ✅ @FindBy annotations are properly initialized
3. ✅ No refactoring needed
4. ✅ Industry standard pattern
5. ✅ Better performance and cleaner code

Never remove PageFactory.initElements() without also:
  - Removing all @FindBy annotations
  - Converting to manual findElements() calls
  - Adding explicit waits where needed
*/
